namespace sv_d92d1f8d17d4436c93c8faaa07b38fc6.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds per-circuit theme state.
/// In Blazor Server, "Scoped" = one instance per circuit (per user tab),
/// so each user gets independent theme state that survives enhanced navigation.
/// </summary>
public sealed class ThemeService
{
    public ThemeMode Mode { get; private set; } = ThemeMode.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    /// <summary>
    /// Fired whenever Mode or AccentColor changes.
    /// Interactive components subscribe to this to re-render.
    /// </summary>
    public event Action? OnThemeChanged;

    public void SetMode(ThemeMode mode)
    {
        if (Mode == mode) return;
        Mode = mode;
        OnThemeChanged?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (string.Equals(AccentColor, color, StringComparison.OrdinalIgnoreCase)) return;
        AccentColor = color;
        OnThemeChanged?.Invoke();
    }

    public void SetTheme(ThemeMode mode, string accentColor)
    {
        var changed = Mode != mode
            || !string.Equals(AccentColor, accentColor, StringComparison.OrdinalIgnoreCase);
        Mode = mode;
        AccentColor = accentColor;
        if (changed) OnThemeChanged?.Invoke();
    }
}

// Applies theme settings to the document root so both static and interactive
// elements are styled consistently.
export function applyTheme(mode, accentColor) {
    const root = document.documentElement;

    root.setAttribute("data-bs-theme", resolveMode(mode));
    root.style.setProperty("--app-accent-color", accentColor);
}

function resolveMode(mode) {
    if (mode === "System") {
        return window.matchMedia("(prefers-color-scheme: dark)").matches
            ? "dark"
            : "light";
    }
    return mode.toLowerCase();
}

