// Applies theme settings to the document root so both static and interactive
// elements are styled consistently.
export function applyTheme(mode, accentColor) {
    const root = document.documentElement;

    root.setAttribute("data-bs-theme", resolveMode(mode));
    root.style.setProperty("--app-accent-color", accentColor);
}

function resolveMode(mode) {
    if (mode === "System") {
        return window.matchMedia("(prefers-color-scheme: dark)").matches
            ? "dark"
            : "light";
    }
    return mode.toLowerCase();
}

@*
    Interactive island embedded in the static layout.
    Because it has @rendermode="InteractiveServer", it lives in the circuit
    and can subscribe to ThemeService events — even though MainLayout is static.
*@
@implements IDisposable
@inject Services.ThemeService Theme
@inject IJSRuntime JS

<span class="badge rounded-pill"
      style="background-color: @Theme.AccentColor; color: white; cursor: default;">
    @ThemeLabel
</span>

@code {
    private IJSObjectReference? _module;

    private string ThemeLabel => Theme.Mode switch
    {
        Services.ThemeMode.Light  => "☀️ Light",
        Services.ThemeMode.Dark   => "🌙 Dark",
        _                         => "💻 System"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/theme.js");
            Theme.OnThemeChanged += HandleThemeChanged;
        }

        // Push current theme to the DOM on every render
        if (_module is not null)
        {
            await _module.InvokeVoidAsync(
                "applyTheme", Theme.Mode.ToString(), Theme.AccentColor);
        }
    }

    private void HandleThemeChanged()
    {
        _ = InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Theme.OnThemeChanged -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject Services.ThemeService Theme

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label fw-semibold">Mode</label>
            <div class="btn-group d-flex" role="group">
                @foreach (var mode in Enum.GetValues<Services.ThemeMode>())
                {
                    var active = mode == Theme.Mode;
                    <button type="button"
                            class="btn @(active ? "btn-primary" : "btn-outline-primary")"
                            @onclick="() => Theme.SetMode(mode)">
                        @mode
                    </button>
                }
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold" for="accent">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input id="accent" type="color"
                       class="form-control form-control-color"
                       value="@Theme.AccentColor"
                       @onchange="OnAccentChanged" />
                <span class="text-muted">@Theme.AccentColor</span>
            </div>
        </div>

        <div class="alert alert-info mb-0">
            Changes apply instantly across all components in your session.
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        Theme.OnThemeChanged += HandleThemeChanged;
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        Theme.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    private void HandleThemeChanged()
    {
        _ = InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Theme.OnThemeChanged -= HandleThemeChanged;
    }
}

