    Because it has @rendermode="InteractiveServer", it lives in the circuit
    and can subscribe to ThemeService events — even though MainLayout is static.
*@
@implements IDisposable
@inject Services.ThemeService Theme
@inject IJSRuntime JS

<span class="badge rounded-pill"
      style="background-color: @Theme.AccentColor; color: white; cursor: default;">
    @ThemeLabel
