@code {
    private IJSObjectReference? _module;

    private string ThemeLabel => Theme.Mode switch
    {
        Services.ThemeMode.Light  => "☀️ Light",
        Services.ThemeMode.Dark   => "🌙 Dark",
        _                         => "💻 System"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/theme.js");
            Theme.OnThemeChanged += HandleThemeChanged;
        }

        // Push current theme to the DOM on every render
        if (_module is not null)
        {
            await _module.InvokeVoidAsync(
                "applyTheme", Theme.Mode.ToString(), Theme.AccentColor);
        }
    }

    private void HandleThemeChanged()
    {
        _ = InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Theme.OnThemeChanged -= HandleThemeChanged;
    }
}

